svg.script:
(async function () {
  const frame = document.getElementById('dominum-frame');
  const svgUrl = new URL(window.location.href);
  const repoBase = svgUrl.href.substring(0, svgUrl.href.lastIndexOf('/') + 1);
  const indexUrl = repoBase + 'index.html';

  function fail(message) {
    frame.srcdoc = `<html><body style="background:#0b0a16;color:#fff;display:grid;place-items:center;height:100vh;font-family:sans-serif;"><div><h2>Load Error</h2><p>${message}</p></div></body></html>`;
  }

  try {
    const response = await fetch(indexUrl);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    let htmlText = await response.text();

    const baseTag = `<base href="${repoBase}">`;
    htmlText = htmlText.replace('<head>', '<head>' + baseTag);

    const blob = new Blob([htmlText], { type: 'text/html' });
    const blobUrl = URL.createObjectURL(blob);

    frame.src = blobUrl;

    frame.onload = () => URL.revokeObjectURL(blobUrl);

  } catch (error) {
    fail(error.message);
  }
})();
